module RefModule (clk, rst, en, ld, si, pi, q);
   input clk, rst, en, ld, si;
   input [7:0] pi;
   output [7:0] q;

   reg [7:0] q;

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
    if (rst) begin
        q <= 8'b00000000;
    end else if (ld) begin
        q <= pi;
    end else if (en) begin
        q <= {si, q[7:1]};
    end
end

endmodule
